#### Issue description

A simple test case that returns an Eigen::Map works fine with v2.0.0 but now segfaults with v2.1.1.  The issue appears to have been introduced with a change on 16 Jan 2017: https://github.com/pybind/pybind11/commit/f86dddf7ba45810c97dc2cf8e8cb6ee1e8477307

This is with python 2.7.2 and gcc 4.9.2

#### Reproducible example code

// The following test case should run fine on v2.0.0 but segfault on v2.1.1
#include "Eigen/Dense"
#include "pybind11/pybind11.h"
#include "pybind11/eigen.h"

namespace py = pybind11;

static Eigen::Map<Eigen::Matrix3i> return_eigen_map() {
  static int array[9];
  for (int ii = 0; ii < 9; ++ii) {
    array[ii] = ii;
  }
  return Eigen::Map<Eigen::Matrix3i>(array);
}

PYBIND11_PLUGIN(test_eigen_map) {
  py::module mm("test_eigen_map", "Eigen Map Tester");
  mm.def("return_eigen_map", &return_eigen_map)
  return mm.ptr();
}

